      interview: [
        { level: "Junior", q: "What is APIView?", a: "The base class for DRF views, providing request/response handling and policy selection (auth/permissions).", type: "Conceptual" },
        { level: "Junior", q: "Difference between a View and a ViewSet?", a: "A View handles standard HTTP methods (get, post). A ViewSet handles actions (list, create, retrieve, update, partial_update, destroy).", type: "Conceptual" },
        { level: "Junior", q: "What are Generic Views?", a: "Pre-built views provided by DRF that implement common patterns like listing objects or creating new ones.", type: "Conceptual" },
        { level: "Junior", q: "What is ModelViewSet?", a: "A class that provides default implementations for a full range of CRUD actions for a model.", type: "Conceptual" },
        { level: "Junior", q: "What is ReadOnlyModelViewSet?", a: "A ViewSet that only provides 'list' and 'retrieve' actions (read-only access).", type: "Conceptual" },
        { level: "Junior", q: "What is the difference between @api_view and APIView?", a: "@api_view is a decorator for function-based views; APIView is a base class for class-based views.", type: "Conceptual" },
        { level: "Junior", q: "Which class based view would you use for a simple list of objects?", a: "ListAPIView or ListCreateAPIView.", type: "Conceptual" },
        { level: "Junior", q: "What are Mixins in DRF?", a: "Small classes that provide a single action like 'list()' or 'create()', which are then combined into generic views.", type: "Conceptual" },
        { level: "Junior", q: "What is the 'queryset' attribute used for in views?", a: "To define the set of model instances that the view should work with.", type: "Conceptual" },
        { level: "Junior", q: "What is the 'serializer_class' attribute for?", a: "To specify which serializer should be used to convert data for this view.", type: "Conceptual" },
        { level: "Junior", q: "How do you handle a DELETE request in a class-based view?", a: "By defining a delete(self, request, *args, **kwargs) method in an APIView.", type: "Coding" },
        { level: "Junior", q: "What is 'perform_create'?", a: "A hook method called by the CreateModelMixin to actually save the object to the database.", type: "Conceptual" },
        { level: "Junior", q: "What is 'perform_update'?", a: "A hook method called by the UpdateModelMixin to actually save changes to an existing object.", type: "Conceptual" },
        { level: "Junior", q: "What is 'perform_destroy'?", a: "A hook method called by the DestroyModelMixin to actually delete the object.", type: "Conceptual" },
        { level: "Junior", q: "How do you specify the primary key in a URL for a Generic View?", a: "By using the <int:pk> or <slug:slug> syntax in your path.", type: "Coding" },
        { level: "Junior", q: "What is 'lookup_field'?", a: "The model field used for looking up individual object instances, defaulting to 'pk'.", type: "Conceptual" },
        { level: "Junior", q: "What is 'lookup_url_kwarg'?", a: "The name of the URL keyword argument that contains the lookup value.", type: "Conceptual" },
        { level: "Junior", q: "Can you use different serializers for different actions in a ViewSet?", a: "Yes, by overriding get_serializer_class().", type: "Conceptual" },
        { level: "Mid", q: "Explain the benefits of using ModelViewSet.", a: "It provides a complete set of default read and write actions, reducing the amount of boilerplate code for standard CRUD APIs.", type: "Conceptual" },
        { level: "Mid", q: "What is the @action decorator?", a: "A way to add extra, custom endpoints to a ViewSet that don't fit the standard CRUD actions.", type: "Conceptual" },
        { level: "Mid", q: "How do you determine the current action in a ViewSet method?", a: "By checking the 'self.action' attribute (e.g., if self.action == 'list').", type: "Coding" },
        { level: "Mid", q: "Why use APIView over Generic Views?", a: "When you need completely custom logic that doesn't follow standard CRUD patterns and want full control over the method handlers.", type: "Scenario" },
        { level: "Mid", q: "Explain the purpose of 'get_queryset()' overrides.", a: "To return a dynamic queryset based on the request user, query params, or other logic.", type: "Scenario" },
        { level: "Mid", q: "What is GenericAPIView?", a: "A base class that adds commonly required behavior for standard list and detail views (queryset, serializer_class, pagination, filtering).", type: "Conceptual" },
        { level: "Mid", q: "How do you implement a search functionality in a View?", a: "By using SearchFilter in filter_backends and defining search_fields.", type: "Coding" },
        { level: "Mid", q: "How do you implement ordering in a View?", a: "By using OrderingFilter in filter_backends and defining ordering_fields.", type: "Coding" },
        { level: "Mid", q: "Explain 'Filtering' in DRF.", a: "The ability to narrow down the queryset based on query parameters using backends like DjangoFilterBackend.", type: "Conceptual" },
        { level: "Mid", q: "How do you restrict the available HTTP methods in a ViewSet?", a: "By setting the 'http_method_names' attribute (e.g., ['get', 'post', 'head']).", type: "Coding" },
        { level: "Mid", q: "What is 'initial(self, request, *args, **kwargs)' in APIView used for?", a: "It's called before the method handler (get/post) to perform tasks like authentication and permission checks.", type: "Conceptual" },
        { level: "Mid", q: "How do you handle exceptions globally in DRF?", a: "By defining a custom function and setting it in EXCEPTION_HANDLER in settings.py.", type: "Scenario" },
        { level: "Senior", q: "Explain the method MRO in GenericAPIView.", a: "It combines Mixins (like ListModelMixin) with the GenericAPIView to provide the actual method implementation.", type: "Conceptual" },
        { level: "Senior", q: "How would you dynamically change the serializer class in a ViewSet?", a: "By overriding the get_serializer_class() method based on the current action or user permissions.", type: "Coding" },
        { level: "Senior", q: "What is the purpose of the 'queryset' attribute being a lazy object?", a: "It allows DRF to modify the query (e.g., adding filters or pagination) before it is actually executed against the database.", type: "Conceptual" },
        { level: "Senior", q: "How do you handle bulk creation in a ViewSet?", a: "Usually by overriding the create() method or using a 3rd party library like 'drf-writable-nested' for complex structures.", type: "Scenario" },
        { level: "Senior", q: "What is the role of the 'dispatch' method?", a: "It is the entry point that handles authentication, permissions, and throttling before calling the actual method handler.", type: "Conceptual" },
        { level: "Senior", q: "How would you implement a 'Soft Delete' pattern in a ViewSet?", a: "By overriding 'perform_destroy' to set an 'is_deleted' flag instead of calling 'delete()'.", type: "Coding" },
        { level: "Senior", q: "Explain how to handle 'Transaction' integrity in a ViewSet that updates multiple models.", a: "Using 'transaction.atomic()' block inside the action method (like create or update).", type: "Scenario" },
        { level: "Senior", q: "How do you optimize a ViewSet that returns data from multiple joined tables?", a: "Using 'select_related' and 'prefetch_related' in get_queryset to avoid the N+1 query problem.", type: "Scenario" },
        { level: "Senior", q: "Explain the difference between 'has_permission' and 'has_object_permission' at the view level.", a: "View calls has_permission first for all requests; has_object_permission is called only during object-level actions (retrieve, update, destroy).", type: "Conceptual" },
        { level: "Senior", q: "How do you implement 'Rate Limiting' for specific actions in a ViewSet?", a: "By overriding 'get_throttles()' to return different throttle classes based on self.action.", type: "Coding" },
        { level: "Senior", q: "How do you handle large-scale media file streaming from a DRF view?", a: "Using FileResponse or streaming response classes, and ensuring the server (Nginx/WhiteNoise) is tuned for large files.", type: "Scenario" },
        { level: "Senior", q: "Explain 'Method Decorators' on class methods (like @method_decorator) vs view decorators.", a: "@method_decorator is used to apply standard Django decorators to class-based view methods.", type: "Conceptual" },
        { level: "Senior", q: "How do you implement a 'Read Only for Public' and 'Full Access for Authed' policy using only ViewSet settings?", a: "Setting permission_classes = [IsAuthenticatedOrReadOnly].", type: "Scenario" },
        { level: "Senior", q: "How do you handle 'Audit Logging' in a ViewSet?", a: "By adding logic in perform_create/perform_update to record changes in a separate log table or using a library like django-simple-history.", type: "Scenario" },
        { level: "Senior", q: "Explain the internal logic of how GenericAPIView maps mixin methods to HTTP methods.", a: "The mixins provide handlers like 'list' or 'create', and the specific generic subclass (like ListCreateAPIView) maps 'get' to 'list' and 'post' to 'create'.", type: "Conceptual" }
      ]
