      interview: [
        { level: "Junior", q: "What is a Router in DRF?", a: "A tool to automatically wire up URL patterns for a ViewSet, following standard REST conventions.", type: "Conceptual" },
        { level: "Junior", q: "Difference between DefaultRouter and SimpleRouter?", a: "DefaultRouter includes a default API root view (listing all registered endpoints) and handles format suffixes for the root.", type: "Conceptual" },
        { level: "Junior", q: "How do you include router URLs in your project?", a: "By adding a path to urls.py and using include(router.urls).", type: "Coding" },
        { level: "Junior", q: "What is the 'basename' parameter in router.register()?", a: "It is the string name used for the generated URL patterns. If not provided, it's generated from the queryset.", type: "Conceptual" },
        { level: "Junior", q: "How do you register a ViewSet with a router?", a: "Using router.register(prefix, viewset_class, basename='name').", type: "Coding" },
        { level: "Junior", q: "What is the purpose of as_view() for ViewSets?", a: "It allows mapping of HTTP methods to ViewSet actions manually (e.g., as_view({'get': 'list'})).", type: "Conceptual" },
        { level: "Junior", q: "Does DRF support automatic URL routing for function-based views?", a: "No, routers only work with ViewSets.", type: "Conceptual" },
        { level: "Junior", q: "What is the default URL for an @action 'my_custom_action'?", a: "/{prefix}/my_custom_action/.", type: "Conceptual" },
        { level: "Junior", q: "How do you change the URL path for an @action?", a: "By using the 'url_path' argument in the decorator, e.g., @action(detail=True, url_path='new-path').", type: "Coding" },
        { level: "Junior", q: "Can you use routers in the main urls.py only?", a: "Yes, or you can define them in app-level urls.py files.", type: "Conceptual" },
        { level: "Junior", q: "What is the relationship between Routers and HTTP methods?", a: "Routers map HTTP methods to specific ViewSet actions (GET -> list/retrieve, POST -> create, etc.).", type: "Conceptual" },
        { level: "Junior", q: "What status code is returned if a URL doesn't match any route?", a: "404 Not Found.", type: "Conceptual" },
        { level: "Junior", q: "What is a prefix in router registration?", a: "The URL segment that precedes the resource actions (e.g., 'users' in /users/...).", type: "Conceptual" },
        { level: "Junior", q: "How many ViewSets can you register on one router?", a: "As many as needed, typically one per resource type.", type: "Conceptual" },
        { level: "Junior", q: "What is 'trailing_slash'?", a: "An argument to the Router class that determines if slashes are appended to generated URLs.", type: "Conceptual" },
        { level: "Junior", q: "What is 'format_suffix_patterns'?", a: "A utility to allow your URLs to handle format suffixes like .json or .xml.", type: "Conceptual" },
        { level: "Junior", q: "What is the value of 'router.urls'?", a: "A list of standard Django URL patterns.", type: "Conceptual" },
        { level: "Junior", q: "How do you handle URLs for many-to-many relationships manually?", a: "Usually by creating specific nested views or actions.", type: "Scenario" },
        { level: "Mid", q: "When would you prefer manual URL configuration over Routers?", a: "When you have a highly custom URL structure that doesn't follow standard REST conventions, or when using APIView.", type: "Scenario" },
        { level: "Mid", q: "What is the 'basename' argument in router.register()?", a: "The name used for the generated URL patterns. If omitted, it defaults to the model name in the queryset.", type: "Conceptual" },
        { level: "Mid", q: "How do you handle nested relationships in URLs?", a: "Using a library like 'drf-nested-routers' to define parent-child URL levels (e.g., /albums/{pk}/tracks/).", type: "Scenario" },
        { level: "Mid", q: "Explain format suffixes in DRF URLs.", a: "DRF can handle URLs like /api/items.json or /api/items.xml using format_suffix_patterns().", type: "Conceptual" },
        { level: "Mid", q: "How do you implement a 'partial' router that only handles certain actions?", a: "By subclassing BaseRouter or using 'as_view' manually for specific paths.", type: "Coding" },
        { level: "Mid", q: "Explain the purpose of the 'detail' argument in @action.", a: "It determines whether the action is for a single object (detail=True) or a collection (detail=False).", type: "Conceptual" },
        { level: "Mid", q: "How do you override the mapping of an HTTP method to a ViewSet action in a Router?", a: "By creating a custom Router class and overriding the 'routes' attribute.", type: "Coding" },
        { level: "Mid", q: "What is the difference between URL path and URL name?", a: "The path is the actual string (host.com/api/users). The name is an identifier for reversing (e.g., 'user-detail').", type: "Conceptual" },
        { level: "Senior", q: "How do routers handle custom @action methods?", a: "They automatically generate URL patterns for them, using the function name as the URL path by default (unless 'url_path' is specified).", type: "Conceptual" },
        { level: "Senior", q: "How would you implement API versioning within a router-based setup?", a: "By creating different routers for different versions and including them under different URL prefixes (/v1/, /v2/).", type: "Scenario" },
        { level: "Senior", q: "What is the benefit of the trailing_slash argument in routers?", a: "It allows you to control whether the generated URLs end with a slash or not, ensuring consistency with your frontend/client requirements.", type: "Conceptual" },
        { level: "Senior", q: "Explain the internal mechanism of how router.urls works.", a: "It is a property that yields a list of URL patterns by inspecting the registered ViewSets and their actions.", type: "Conceptual" },
        { level: "Senior", q: "Can you register the same ViewSet twice in a router?", a: "Yes, with different prefixes and basenames, usually to provide different filters or behaviors for the same model.", type: "Scenario" },
        { level: "Senior", q: "How would you implement a Router that automatically adds 'lookup_field' regex into the paths?", a: "By overriding the 'get_lookup_regex' method in a custom router class.", type: "Coding" },
        { level: "Senior", q: "Explain the 'Route' and 'DynamicRoute' named tuples in DRF source.", a: "Route defines standard CRUD actions; DynamicRoute defines how @action methods are transformed into URL patterns.", type: "Conceptual" },
        { level: "Senior", q: "How do you implement a 'namespaced' API using routers?", a: "By passing the 'app_name' or 'namespace' argument to include(router.urls).", type: "Coding" },
        { level: "Senior", q: "How would you handle URL routing for a 'Slug-only' API where IDs are never exposed?", a: "Set 'lookup_field = slug' in the viewset and ensure the router uses the correct regex via ViewSet attributes.", type: "Scenario" },
        { level: "Senior", q: "Explain 'Format Suffix' negotiation internals.", a: "DRF appends a (.?P<format>[a-z0-9]+)/? group to the regex to capture the requested extension.", type: "Conceptual" },
        { level: "Senior", q: "How do you optimize URL resolution time for an API with hundreds of routes?", a: "By grouping routes into apps and using nested 'include' calls to minimize the depth of the search tree.", type: "Scenario" },
        { level: "Senior", q: "What is the difference between 'as_view' and 'include(router.urls)' in terms of URL pattern generation?", a: "'as_view' creates a single pattern; 'include(router.urls)' generates a full set of RESTful paths for all actions.", type: "Conceptual" }
      ]
